async (page) => {
  // Get all comments and analyze their structure
  const comments = await page.evaluate(() => {
    const allRows = document.querySelectorAll('table table');
    const commentData = [];

    allRows.forEach((table, index) => {
      const cells = table.querySelectorAll('td');
      if (cells.length >= 2) {
        const secondCell = cells[1];
        const linkElements = secondCell.querySelectorAll('a');
        const userLink = Array.from(linkElements).find(a => a.href.includes('user?id='));
        const timeLink = Array.from(linkElements).find(a => a.href.includes('item?id='));
        const parentLink = Array.from(linkElements).find(a => a.textContent === 'parent');
        const prevLink = Array.from(linkElements).find(a => a.textContent === 'prev');
        const rootLink = Array.from(linkElements).find(a => a.textContent === 'root');

        if (userLink && timeLink) {
          commentData.push({
            index: index,
            user: userLink.textContent,
            id: timeLink.href.split('id=')[1],
            hasParent: !!parentLink,
            hasPrev: !!prevLink,
            hasRoot: !!rootLink,
            parentText: parentLink ? parentLink.textContent : null,
            rootText: rootLink ? rootLink.textContent : null,
            prevText: prevLink ? prevLink.textContent : null
          });
        }
      }
    });
    return commentData;
  });

  return comments.slice(0, 30);
}

